// normaliza o payload de entrada para os passos seguintes
const b = $json.body || $json;
const subject = {
  predio_curto: b.imovel?.predio_curto || '',
  logradouro: (b.imovel?.ficha?.find(f => /endere/i.test(f[0]))?.[1]) || b.endereco || '',
  numero: b.numero || '',
  building_key: b.building_key || b.buildingKey || ''
};
const avaliando = b.avaliando || {
  tipo: 'avaliando', nome: (b.imovel?.predio_curto || 'Avaliando') + ' (avaliando)',
  bairro: b.imovel?.bairro || '', area: '', suites: '', vagas: '',
  pedido: b.pedido_atual || '', valor: b.valor_atual || 0, valor_m2: ''
};
return [{ json: {
  buildingKey: subject.building_key,
  subject, avaliando,
  urls: b.links || [],
  imovel: b.imovel, corretor: b.corretor,
  estudo_data: b.estudo_data, ref: b.ref
} }];

// guarda os dados do estudo + candidatos para depois da aprovação
const base = $('Parse intake').item.json;
return [{ json: { ...base, amostras: $json.amostras, aprovacao: $json.aprovacao } }];

// aplica a resposta do admin sobre os candidatos.
// Espera a resposta do admin em $json.resposta (ligar ao retorno da cascata de aprovação).
let amostras = $('Juntar p/ aprovação').item.json.amostras;
const r = ($json.resposta || 'ok').toString().trim().toLowerCase();
const rem = [...r.matchAll(/remover\s+(\d+)/g)].map(m => parseInt(m[1], 10));
if (rem.length) {
  const cand = amostras.filter(a => a.tipo !== 'avaliando');
  const drop = new Set(rem.map(n => n - 1));
  amostras = [amostras.find(a => a.tipo === 'avaliando'), ...cand.filter((_, i) => !drop.has(i))].filter(Boolean);
}
const base = $('Juntar p/ aprovação').item.json;
return [{ json: { ...base, amostras } }];
